SELECT * FROM approval_delegation
WHERE delegator_id = #{delegatorId}
ORDER BY create_time DESC

SELECT * FROM approval_delegation
WHERE delegator_id = #{delegatorId}
  AND status = 1
  AND start_time <= #{now}
  AND end_time >= #{now}
ORDER BY create_time DESC
LIMIT 1

SELECT COUNT(*) FROM approval_delegation
WHERE delegator_id = #{delegatorId}
  AND status = 1
  AND start_time < #{endTime}
  AND end_time > #{startTime}
